SELECT SUM(entry_id) AS total_identifiers
FROM portfolio_entries
WHERE portfolio_id = 1;

SELECT total_value
FROM portfolio_versions
WHERE portfolio_id = 0 AND version_date = '2023-05-01';

SELECT SUM(pe.weight * pe.shares_out * pe.price) AS total_value
FROM portfolio_entries pe
WHERE pe.weight > 0 AND pe.portfolio_id = 0;

SELECT pe.date, c.name
FROM portfolio_entries pe
INNER JOIN companies c ON pe.ticker = c.ticker;

SELECT portfolio_id, COUNT(entry_id) AS total_seeds
FROM portfolio_entries
GROUP BY portfolio_id;

SELECT c.name
FROM companies c
INNER JOIN portfolio_entries pe ON c.ticker = pe.ticker;
